const rawTable = $input.first().json.message.content;

// Split into rows and filter empty lines
const rows = rawTable.split('\n').filter(row => row.trim() !== '');

// Extract headers (first row)
const headers = rows[0]
  .split('|')
  .slice(1, -1)
  .map(h => h.trim());

// Process data rows (skip second separator row)
const jsonData = [];
for (let i = 2; i < rows.length; i++) {
  const columns = rows[i]
    .split('|')
    .slice(1, -1)
    .map(c => c.trim());

  jsonData.push({
    [headers[0]]: columns[0],
    [headers[1]]: columns[1],
    [headers[2]]: columns[2].replace(/<br>/g, '\n') // Convert <br> to newlines
  });
}

return jsonData;
